final:
module RefModule(
    input clk,
    input reset,
    input serial_in,
    output [3:0] parallel_out
);reg [3:0] obf_shift_reg;

always @(posedge clk) begin
    if (reset) begin
        obf_shift_reg <= 4'b0;
    end else begin
        obf_shift_reg <= {obf_shift_reg[2:0], serial_in};
    end
end

assign parallel_out = obf_shift_reg;

endmodule
